import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer } from 'recharts';
import { fmtRp } from '../../utils/format';
import { CHART_COLORS } from '../../utils/constants';

const tooltipStyle = {
  contentStyle: { background:'#fff', border:'1px solid #dde3ec', borderRadius:10, fontFamily:'Sora,sans-serif', fontSize:12 },
};

const renderLabel = ({ name, percent }) =>
  percent > 0.05 ? `${name.length > 10 ? name.slice(0,10)+'…' : name} ${(percent*100).toFixed(0)}%` : '';

export default function PieChartKategori({ data, height = 220 }) {
  if (!data || data.length === 0) {
    return (
      <div className="empty-state">
        <div className="empty-state-icon">📊</div>
        <p>Belum ada data pengeluaran</p>
      </div>
    );
  }
  return (
    <ResponsiveContainer width="100%" height={height}>
      <PieChart>
        <Pie data={data} cx="50%" cy="50%" outerRadius={85} dataKey="value"
          label={renderLabel} labelLine={false} fontSize={10}>
          {data.map((_,i) => <Cell key={i} fill={CHART_COLORS[i % CHART_COLORS.length]} />)}
        </Pie>
        <Tooltip formatter={v => [fmtRp(v)]} {...tooltipStyle} />
      </PieChart>
    </ResponsiveContainer>
  );
}
